import json

url = "https://partner.shopeemobile.com/api/v2/logistics/download_to_label?access_token=access_token&partner_id=partner_id&shop_id=shop_id&sign=sign&timestamp=timestamp"

payload=json.dumps({
  "quantity": 1,
  "sorting_group": 1
})
